CustomCSS:
/* VORA Google Blogger Grid Redesign */

/* 1. 기본 배경 및 폰트 세팅 */
body {
  background-color: #0f1115;
  color: #e2e8f0;
  font-family: 'Inter', -apple-system, sans-serif;
}

/* 2. 블로그 포스트 컨테이너 그리드화 */
.blog-posts {
  display: flex !important;
  flex-wrap: wrap !important;
  justify-content: space-between !important;
  width: 100%;
  padding: 20px 0;
}

/* 3. 개별 포스트 카드 디자인 (3열 배치) */
.date-outer, .post-outer {
  width: 31%; /* 3열을 위한 너비 할당 */
  margin-bottom: 30px;
  background: #1a1d24;
  border-radius: 12px;
  overflow: hidden;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);
  display: flex;
  flex-direction: column;
}

/* 4. 마우스 호버(Hover) 시 다이나믹 애니메이션 */
.post-outer:hover {
  transform: translateY(-8px);
  box-shadow: 0 12px 28px rgba(0, 200, 255, 0.15);
  border-color: rgba(255, 255, 255, 0.1);
}

/* 5. 텍스트 요소 패딩 및 간격 조정 */
.post-title {
  font-size: 1.3rem;
  font-weight: 700;
  margin: 20px;
  color: #ffffff;
  line-height: 1.4;
}
.post-body {
  padding: 0 20px 20px 20px;
  color: #94a3b8;
  font-size: 0.95rem;
  line-height: 1.6;
}

/* 공간을 차지하는 불필요한 메타데이터 숨김 (옵션) */
.post-footer {
  padding: 15px 20px;
  background: #14161a;
  border-top: 1px solid #2d3748;
}

/* 6. 반응형(모바일/태블릿) 설정 */
@media (max-width: 992px) {
  .date-outer, .post-outer {
    width: 48%; /* 태블릿에서는 2열 */
  }
}

@media (max-width: 600px) {
  .date-outer, .post-outer {
    width: 100%; /* 모바일에서는 1열 */
    margin-bottom: 20px;
  }
}
